import React from 'react'
import ucsfLogo from './images/ucsfHealth.jpg'
import { properties } from '../../properties/properties.js'

const CHAT_ENDPOINT = `${properties.backend}rag_chatbot/rag_chatbot/chat`
const UPLOAD_PDF_ENDPOINT = `${properties.backend}rag_chatbot/rag_chatbot/upload-pdf`

const desktopTopStyle = {
    width: "100%", backgroundColor: "#052049", color: "#ffffff", height: "40px", fontSize: "14px"
}

function generateId() {
    return Math.random().toString(36).slice(2, 10)
}

function getTimestamp() {
    return new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
}

class ChatbotApp extends React.Component {

    constructor(props) {
        super(props)
        this.state = {
            // Sessions
            sessions: [{ id: generateId(), name: 'New Chat', messages: [], createdAt: getTimestamp() }],
            activeSessionId: null,

            // Input
            inputValue: '',
            loading: false,

            // PDF upload
            uploadedDocs: [],
            uploadStatus: null,   // { type: 'success' | 'error' | 'loading', msg: '' }

            // Sidebar
            sidebarOpen: true
        }
        this.fileInputRef = React.createRef()
        this.textareaRef = React.createRef()
        this.messagesEndRef = React.createRef()
    }

    componentDidMount() {
        var sessions = this.state.sessions
        this.setState({ activeSessionId: sessions[0].id })
    }

    componentDidUpdate(prevProps, prevState) {
        // Auto-scroll to bottom when messages change
        if (prevState.sessions !== this.state.sessions || prevState.loading !== this.state.loading) {
            this.scrollToBottom()
        }
    }

    scrollToBottom() {
        if (this.messagesEndRef.current) {
            this.messagesEndRef.current.scrollIntoView({ behavior: 'smooth' })
        }
    }

    // ── Session management ──────────────────────────────────────────────────

    getActiveSession() {
        var self = this
        return this.state.sessions.find(function(s) { return s.id === self.state.activeSessionId }) || null
    }

    createNewSession() {
        var newSession = { id: generateId(), name: 'New Chat', messages: [], createdAt: getTimestamp() }
        var sessions = [newSession].concat(this.state.sessions)
        this.setState({ sessions: sessions, activeSessionId: newSession.id, inputValue: '' })
    }

    deleteSession(id, e) {
        e.stopPropagation()
        var sessions = this.state.sessions.filter(function(s) { return s.id !== id })
        var newActiveId = this.state.activeSessionId

        if (this.state.activeSessionId === id) {
            if (sessions.length > 0) {
                newActiveId = sessions[0].id
            } else {
                var fresh = { id: generateId(), name: 'New Chat', messages: [], createdAt: getTimestamp() }
                sessions = [fresh]
                newActiveId = fresh.id
            }
        }
        this.setState({ sessions: sessions, activeSessionId: newActiveId })
    }

    switchSession(id) {
        if (id !== this.state.activeSessionId) {
            this.setState({ activeSessionId: id, inputValue: '' })
        }
    }

    updateSessionName(sessionId, firstUserMsg) {
        var name = firstUserMsg.slice(0, 30) + (firstUserMsg.length > 30 ? '…' : '')
        var sessions = this.state.sessions.map(function(s) {
            return s.id === sessionId ? Object.assign({}, s, { name: name }) : s
        })
        this.setState({ sessions: sessions })
    }

    appendMessageToSession(sessionId, message) {
        var sessions = this.state.sessions.map(function(s) {
            if (s.id !== sessionId) return s
            return Object.assign({}, s, { messages: s.messages.concat([message]) })
        })
        this.setState({ sessions: sessions })
    }

    // ── PDF Upload ──────────────────────────────────────────────────────────

    handleFileUpload(e) {
        var file = e.target.files[0]
        if (!file) return
        if (file.type !== 'application/pdf') {
            this.setState({ uploadStatus: { type: 'error', msg: 'Only PDF files are supported.' } })
            return
        }

        this.setState({ uploadStatus: { type: 'loading', msg: 'Uploading ' + file.name + '…' } })

        var formData = new FormData()
        formData.append('pdf', file)

        var self = this
        fetch(UPLOAD_PDF_ENDPOINT, { method: 'POST', body: formData })
            .then(function(res) { return res.json() })
            .then(function(data) {
                if (data.error) throw new Error(data.error)
                var docs = self.state.uploadedDocs.concat([{ name: file.name, id: data.documentId, chunks: data.chunks }])
                self.setState({
                    uploadedDocs: docs,
                    uploadStatus: { type: 'success', msg: '✓ ' + file.name + ' indexed (' + data.chunks + ' chunks)' }
                })
                setTimeout(function() { self.setState({ uploadStatus: null }) }, 4000)
            })
            .catch(function(err) {
                self.setState({ uploadStatus: { type: 'error', msg: err.message || 'Upload failed' } })
                setTimeout(function() { self.setState({ uploadStatus: null }) }, 4000)
            })

        e.target.value = ''
    }

    // ── Send Message ────────────────────────────────────────────────────────

    sendMessage() {
        var text = this.state.inputValue.trim()
        if (!text || this.state.loading) return

        var sessionId = this.state.activeSessionId
        var activeSession = this.getActiveSession()
        if (!activeSession) return

        var userMsg = { id: generateId(), role: 'user', content: text, time: getTimestamp() }

        // Append user message
        this.appendMessageToSession(sessionId, userMsg)

        // Name the session from first message
        if (activeSession.messages.length === 0) {
            this.updateSessionName(sessionId, text)
        }

        this.setState({ inputValue: '', loading: true })

        // Build history from current session messages (before this new message)
        var history = activeSession.messages.map(function(m) {
            return { role: m.role, content: m.content }
        })

        var self = this
        var headers = new Headers()
        headers.append('Content-Type', 'application/json')
        headers.append('Accept', 'application/json')

        fetch(CHAT_ENDPOINT, {
            method: 'POST',
            headers: headers,
            body: JSON.stringify({
                sessionId: sessionId,
                message: text,
                history: history      // full conversation history for session continuity
            })
        })
        .then(function(res) { return res.json() })
        .then(function(data) {
            if (data.error) throw new Error(data.error)
            var assistantMsg = {
                id: generateId(),
                role: 'assistant',
                content: data.reply,
                sources: data.sources || [],
                time: getTimestamp()
            }
            self.appendMessageToSession(sessionId, assistantMsg)
            self.setState({ loading: false })
        })
        .catch(function(err) {
            var errMsg = {
                id: generateId(),
                role: 'error',
                content: 'Error: ' + (err.message || 'Request failed'),
                time: getTimestamp()
            }
            self.appendMessageToSession(sessionId, errMsg)
            self.setState({ loading: false })
        })
    }

    handleKeyDown(e) {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault()
            this.sendMessage()
        }
    }

    handleInputChange(e) {
        this.setState({ inputValue: e.target.value })
        var ta = e.target
        ta.style.height = 'auto'
        ta.style.height = Math.min(ta.scrollHeight, 120) + 'px'
    }

    // ── Render: Sidebar ─────────────────────────────────────────────────────

    renderSidebar() {
        if (!this.state.sidebarOpen) return null

        var self = this
        var uploadStatus = this.state.uploadStatus

        return (
            <div style={{ width: "240px", background: "#f0f2f5", borderRight: "1px solid #e2e6ed", display: "flex", flexDirection: "column", flexShrink: 0 }}>

                {/* New Chat Button */}
                <div style={{ padding: "12px" }}>
                    <button
                        onClick={function() { self.createNewSession() }}
                        style={{
                            width: "100%", padding: "9px 12px", background: "#052049", color: "#ffffff",
                            border: "none", borderRadius: "5px", fontSize: "13px", fontWeight: "600",
                            cursor: "pointer", display: "flex", alignItems: "center", gap: "8px", justifyContent: "center"
                        }}
                    >
                        <span style={{ fontSize: "16px", lineHeight: 1 }}>+</span> New Chat
                    </button>
                </div>

                {/* Session List */}
                <div style={{ flex: 1, overflowY: "auto", padding: "0 8px" }}>
                    <div style={{ fontSize: "11px", fontWeight: "700", color: "#7c8ba1", textTransform: "uppercase", letterSpacing: "0.5px", padding: "6px 6px 4px" }}>
                        Conversations
                    </div>
                    {this.state.sessions.map(function(s) {
                        var isActive = s.id === self.state.activeSessionId
                        return (
                            <div
                                key={s.id}
                                onClick={function() { self.switchSession(s.id) }}
                                style={{
                                    padding: "9px 10px", borderRadius: "5px", marginBottom: "2px",
                                    cursor: "pointer",
                                    background: isActive ? "#052049" : "transparent",
                                    display: "flex", alignItems: "center", justifyContent: "space-between"
                                }}
                            >
                                <div style={{ overflow: "hidden" }}>
                                    <div style={{
                                        fontSize: "12px", fontWeight: isActive ? "600" : "400",
                                        color: isActive ? "#ffffff" : "#2c3345",
                                        whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis", maxWidth: "160px"
                                    }}>
                                        {s.name}
                                    </div>
                                    <div style={{ fontSize: "11px", color: isActive ? "#a0b4cc" : "#7c8ba1", marginTop: "1px" }}>
                                        {s.createdAt}
                                    </div>
                                </div>
                                <button
                                    onClick={function(e) { self.deleteSession(s.id, e) }}
                                    style={{
                                        background: "none", border: "none", cursor: "pointer",
                                        color: isActive ? "#a0b4cc" : "#7c8ba1",
                                        padding: "2px 4px", fontSize: "14px", lineHeight: 1, flexShrink: 0
                                    }}
                                    title="Delete"
                                >
                                    ✕
                                </button>
                            </div>
                        )
                    })}
                </div>

                {/* PDF Upload */}
                <div style={{ padding: "12px", borderTop: "1px solid #e2e6ed" }}>
                    <div style={{ fontSize: "11px", fontWeight: "700", color: "#7c8ba1", textTransform: "uppercase", letterSpacing: "0.5px", marginBottom: "8px" }}>
                        Knowledge Base
                    </div>
                    <button
                        onClick={function() { self.fileInputRef.current.click() }}
                        style={{
                            width: "100%", padding: "8px", background: "#ffffff",
                            border: "1px dashed #b0bec5", borderRadius: "5px",
                            color: "#052049", fontSize: "12px", fontWeight: "600",
                            cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: "6px"
                        }}
                    >
                        ↑ Upload PDF
                    </button>
                    <input
                        ref={this.fileInputRef}
                        type="file"
                        accept=".pdf"
                        onChange={function(e) { self.handleFileUpload(e) }}
                        style={{ display: "none" }}
                    />

                    {uploadStatus && (
                        <div style={{
                            marginTop: "8px", fontSize: "11px", padding: "6px 8px", borderRadius: "4px",
                            background: uploadStatus.type === 'success' ? "#e6f5ec" : uploadStatus.type === 'error' ? "#fde8ec" : "#e8edf5",
                            color: uploadStatus.type === 'success' ? "#0e7c3a" : uploadStatus.type === 'error' ? "#9f1239" : "#052049",
                            border: "1px solid " + (uploadStatus.type === 'success' ? "#b2dfcc" : uploadStatus.type === 'error' ? "#f5b8c4" : "#c5d0e0")
                        }}>
                            {uploadStatus.msg}
                        </div>
                    )}

                    {this.state.uploadedDocs.length > 0 && (
                        <div style={{ marginTop: "8px" }}>
                            {this.state.uploadedDocs.map(function(doc, i) {
                                return (
                                    <div key={i} style={{ display: "flex", alignItems: "center", gap: "6px", padding: "5px 0", borderBottom: "1px solid #e2e6ed" }}>
                                        <span style={{ fontSize: "13px" }}>📄</span>
                                        <span style={{ fontSize: "11px", color: "#2c3345", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                                            {doc.name}
                                        </span>
                                    </div>
                                )
                            })}
                        </div>
                    )}
                </div>
            </div>
        )
    }

    // ── Render: Messages ────────────────────────────────────────────────────

    renderMessages() {
        var activeSession = this.getActiveSession()
        if (!activeSession) return null

        var messages = activeSession.messages
        var self = this

        if (messages.length === 0 && !this.state.loading) {
            return (
                <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", color: "#7c8ba1", fontSize: "14px", flexDirection: "column", gap: "10px" }}>
                    <div style={{ fontSize: "32px" }}>💬</div>
                    <div>Start a conversation or upload a PDF to begin</div>
                </div>
            )
        }

        return (
            <div style={{ flex: 1, overflowY: "auto", padding: "20px" }}>
                <div style={{ maxWidth: "800px", margin: "0 auto" }}>
                    {messages.map(function(msg) {
                        var isUser = msg.role === 'user'
                        var isError = msg.role === 'error'

                        return (
                            <div key={msg.id} style={{ marginBottom: "16px", display: "flex", flexDirection: isUser ? "row-reverse" : "row", gap: "10px", alignItems: "flex-start" }}>
                                {/* Avatar */}
                                {!isUser && (
                                    <div style={{
                                        width: "30px", height: "30px", borderRadius: "50%", flexShrink: 0,
                                        background: isError ? "#fde8ec" : "#e8edf5",
                                        border: "1px solid " + (isError ? "#f5b8c4" : "#c5d0e0"),
                                        display: "flex", alignItems: "center", justifyContent: "center", fontSize: "14px"
                                    }}>
                                        {isError ? "⚠" : "🤖"}
                                    </div>
                                )}

                                <div style={{ maxWidth: "75%" }}>
                                    {/* Bubble */}
                                    <div style={{
                                        padding: "10px 14px",
                                        borderRadius: isUser ? "12px 2px 12px 12px" : "2px 12px 12px 12px",
                                        background: isUser ? "#052049" : isError ? "#fde8ec" : "#ffffff",
                                        border: "1px solid " + (isUser ? "#052049" : isError ? "#f5b8c4" : "#e2e6ed"),
                                        color: isUser ? "#ffffff" : isError ? "#9f1239" : "#2c3345",
                                        fontSize: "13px", lineHeight: "1.65"
                                    }}>
                                        <p style={{ margin: 0, whiteSpace: "pre-wrap" }}>{msg.content}</p>
                                    </div>

                                    {/* RAG Sources */}
                                    {msg.sources && msg.sources.length > 0 && (
                                        <div style={{ marginTop: "5px", display: "flex", gap: "5px", flexWrap: "wrap" }}>
                                            {msg.sources.map(function(src, i) {
                                                return (
                                                    <span key={i} style={{
                                                        fontSize: "10px", color: "#0369a1", background: "#e6f3fb",
                                                        border: "1px solid #b3d8f0", borderRadius: "3px", padding: "2px 6px"
                                                    }}>
                                                        📎 {src}
                                                    </span>
                                                )
                                            })}
                                        </div>
                                    )}

                                    <div style={{ fontSize: "11px", color: "#7c8ba1", marginTop: "4px", textAlign: isUser ? "right" : "left" }}>
                                        {msg.time}
                                    </div>
                                </div>
                            </div>
                        )
                    })}

                    {/* Typing indicator */}
                    {this.state.loading && (
                        <div style={{ display: "flex", gap: "10px", alignItems: "flex-start", marginBottom: "16px" }}>
                            <div style={{ width: "30px", height: "30px", borderRadius: "50%", flexShrink: 0, background: "#e8edf5", border: "1px solid #c5d0e0", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "14px" }}>
                                🤖
                            </div>
                            <div style={{ padding: "12px 16px", borderRadius: "2px 12px 12px 12px", background: "#ffffff", border: "1px solid #e2e6ed" }}>
                                <div style={{ display: "flex", gap: "4px", alignItems: "center" }}>
                                    {[0, 1, 2].map(function(i) {
                                        return (
                                            <div key={i} style={{
                                                width: "7px", height: "7px", borderRadius: "50%", background: "#052049",
                                                animation: "chatbotPulse 1.2s infinite",
                                                animationDelay: (i * 0.2) + "s"
                                            }} />
                                        )
                                    })}
                                </div>
                            </div>
                        </div>
                    )}

                    <div ref={this.messagesEndRef} />
                </div>
            </div>
        )
    }

    // ── Render: Input Bar ───────────────────────────────────────────────────

    renderInputBar() {
        var self = this
        var disabled = this.state.loading || !this.state.inputValue.trim()

        return (
            <div style={{ padding: "12px 20px 16px", borderTop: "1px solid #e2e6ed", background: "#fafbfc", flexShrink: 0 }}>
                <div style={{ maxWidth: "800px", margin: "0 auto", display: "flex", gap: "10px", alignItems: "flex-end", background: "#ffffff", border: "1px solid #e2e6ed", borderRadius: "8px", padding: "10px 12px", boxShadow: "0 1px 4px rgba(5,32,73,0.06)" }}>
                    <textarea
                        ref={this.textareaRef}
                        value={this.state.inputValue}
                        onChange={function(e) { self.handleInputChange(e) }}
                        onKeyDown={function(e) { self.handleKeyDown(e) }}
                        placeholder="Ask anything… (Shift+Enter for new line)"
                        rows={1}
                        style={{
                            flex: 1, resize: "none", outline: "none", border: "none",
                            background: "transparent", fontFamily: "Arial, sans-serif",
                            fontSize: "13px", lineHeight: "1.6", color: "#2c3345",
                            maxHeight: "120px", overflowY: "auto"
                        }}
                    />
                    <button
                        onClick={function() { self.sendMessage() }}
                        disabled={disabled}
                        style={{
                            width: "36px", height: "36px", borderRadius: "6px",
                            background: disabled ? "#e2e6ed" : "#052049",
                            border: "none", cursor: disabled ? "not-allowed" : "pointer",
                            display: "flex", alignItems: "center", justifyContent: "center",
                            color: disabled ? "#7c8ba1" : "#ffffff", flexShrink: 0,
                            fontSize: "16px"
                        }}
                    >
                        ➤
                    </button>
                </div>
                <div style={{ maxWidth: "800px", margin: "5px auto 0", fontSize: "11px", color: "#7c8ba1", textAlign: "center" }}>
                    RAG-augmented · Session-aware · UCSF GPT-4o
                </div>
            </div>
        )
    }

    // ── Main Render ─────────────────────────────────────────────────────────

    render() {
        var self = this

        return (
            <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column" }}>

                {/* Typing animation keyframes */}
                <style>{`
                    @keyframes chatbotPulse {
                        0%, 100% { opacity: 1; transform: scale(1); }
                        50% { opacity: 0.3; transform: scale(0.8); }
                    }
                `}</style>

                {/* Top bar */}
                <div style={desktopTopStyle}>
                    <span style={{ left: "30px", top: "10px", position: "relative" }}>
                        University of California San Francisco
                    </span>
                </div>

                {/* Header */}
                <div style={{ width: "100%", height: "100px", boxShadow: "0px 0px 8px 2px #CCCCCC" }}>
                    <div style={{ marginLeft: "4%" }}>
                        <div style={{ float: "left", display: "grid", height: "100px" }}>
                            <img src={ucsfLogo} style={{ height: "30px", margin: "auto" }} alt="UCSF Logo" />
                        </div>
                        <div style={{ float: "left", marginLeft: "30px", fontFamily: "Arial", fontSize: "18px", height: "100px", display: "grid" }}>
                            <span style={{ margin: "auto" }}>- AI Assistant</span>
                        </div>
                        <div style={{ float: "right", marginRight: "4%", height: "100px", display: "grid" }}>
                            <button
                                onClick={function() { self.setState({ sidebarOpen: !self.state.sidebarOpen }) }}
                                style={{
                                    margin: "auto", padding: "6px 14px", background: "transparent",
                                    border: "1px solid #c5d0e0", borderRadius: "5px",
                                    color: "#052049", fontSize: "12px", fontWeight: "600", cursor: "pointer"
                                }}
                            >
                                {this.state.sidebarOpen ? '◀ Hide Panel' : '▶ Show Panel'}
                            </button>
                        </div>
                    </div>
                </div>

                {/* Main layout: sidebar + chat */}
                <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
                    {this.renderSidebar()}

                    {/* Chat area */}
                    <div style={{ flex: 1, display: "flex", flexDirection: "column", minWidth: 0, background: "#f7f9fb" }}>
                        {this.renderMessages()}
                        {this.renderInputBar()}
                    </div>
                </div>
            </div>
        )
    }
}

export default ChatbotApp
